sql:
SELECT dataset_id
FROM dataset_access
WHERE user_id = 1;

SELECT databases.database_name, databases.description, databases.size_gb, taxonomies.scientific_name, taxonomies.common_name
FROM databases
INNER JOIN taxonomies ON databases.database_id = taxonomies.tax_id;

SELECT query, results, search_type, search_time
FROM sequence_search
WHERE user_id = 1;

SELECT COUNT(access_id) AS times_accessed
FROM dataset_access
WHERE user_id = 'user_id_here';

SELECT COUNT(DISTINCT t.species)
FROM taxonomies t
WHERE t.tax_id IN (
    SELECT DISTINCT gs.sequence_id 
    FROM genomic_sequences gs
);

external_knowledge:
- 'large databases' refers to databases with a size greater than 1000 GB;
- 'scientists' are users with the role 'scientist';
- 'dawn of a new decade' refers to the date '2020-12-31', marking the end of the year 2020 and, by extension, the decade.

sql:
SELECT COUNT(*) AS sequence_count
FROM genomic_sequences
WHERE is_consensus = 1;

SELECT
    (SELECT SUM(size_gb) FROM databases WHERE is_public = 1) / 
    (SELECT SUM(size_gb) FROM databases) AS public_to_total_ratio;

external_knowledge:
- A genomic sequence is a string of nucleotides (A, C, G, and T) that make up an organism's DNA or RNA; 
- Annotations provide additional information about specific parts of a genomic sequence, such as the location of genes or regulatory elements; 
- Taxonomic classification is a way of grouping living things based on their shared characteristics and evolutionary relationships.

sql:
SELECT HEX(sequence) AS sequence_hex
FROM genomic_sequences
WHERE sequence_id = 1;
